import React, { useState } from 'react';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

function Workflows() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runWorkflow = async (type) => {
    setLoading(true);
    setResult(null);

    let prompt = '';
    if (type === 'market') {
      prompt = 'Give me a 1-sentence Austin TX real estate market summary for 2025';
    } else if (type === 'lead') {
      prompt = 'Write a simple 1-sentence follow-up email for a real estate lead';
    } else if (type === 'listing') {
      prompt = 'Write a 1-sentence property listing description';
    }

    try {
      const response = await fetch(`${API_URL}/ai_chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: prompt })
      });
      const data = await response.json();
      setResult(data.response || data);
    } catch (error) {
      setResult({ error: error.message });
    }
    setLoading(false);
  }

  return (
    <div style={{ maxWidth: '600px', margin: '0 auto', textAlign: 'left' }}>
      <h2>⚙️ Quick Workflows</h2>
      <p style={{ color: '#8b949e', marginBottom: '1.5rem' }}>
        Click any button to generate instant results
      </p>

      <div style={{ display: 'grid', gap: '1rem' }}>
        <button 
          onClick={() => runWorkflow('market')}
          disabled={loading}
          style={{
            background: 'linear-gradient(135deg, #1e3a5f, #2d5a87)',
            color: 'white',
            border: 'none',
            padding: '1.5rem',
            borderRadius: '12px',
            cursor: loading ? 'not-allowed' : 'pointer',
            textAlign: 'left'
          }}
        >
          <div style={{ fontWeight: '600', fontSize: '1.1rem' }}>📊 Market Summary</div>
          <div style={{ fontSize: '0.85rem', opacity: 0.8, marginTop: '0.25rem' }}>
            Get a quick Austin real estate market overview
          </div>
        </button>

        <button 
          onClick={() => runWorkflow('lead')}
          disabled={loading}
          style={{
            background: 'linear-gradient(135deg, #3d5a1e, #4a7a23)',
            color: 'white',
            border: 'none',
            padding: '1.5rem',
            borderRadius: '12px',
            cursor: loading ? 'not-allowed' : 'pointer',
            textAlign: 'left'
          }}
        >
          <div style={{ fontWeight: '600', fontSize: '1.1rem' }}>✉️ Lead Follow-up</div>
          <div style={{ fontSize: '0.85rem', opacity: 0.8, marginTop: '0.25rem' }}>
            Generate a quick follow-up email
          </div>
        </button>

        <button 
          onClick={() => runWorkflow('listing')}
          disabled={loading}
          style={{
            background: 'linear-gradient(135deg, #5a3d1e, #7a4a23)',
            color: 'white',
            border: 'none',
            padding: '1.5rem',
            borderRadius: '12px',
            cursor: loading ? 'not-allowed' : 'pointer',
            textAlign: 'left'
          }}
        >
          <div style={{ fontWeight: '600', fontSize: '1.1rem' }}>🏠 Property Listing</div>
          <div style={{ fontSize: '0.85rem', opacity: 0.8, marginTop: '0.25rem' }}>
            Create a listing description
          </div>
        </button>
      </div>

      {loading && (
        <div style={{ marginTop: '1.5rem', textAlign: 'center', color: '#8b949e' }}>
          ⏳ Running... (may take 10-30 seconds)
        </div>
      )}

      {result && (
        <div style={{ 
          marginTop: '1.5rem',
          background: 'rgba(0,0,0,0.4)', 
          borderRadius: '12px', 
          padding: '1.5rem'
        }}>
          <div style={{ color: '#8b949e', marginBottom: '0.5rem' }}>Result:</div>
          <div style={{ color: '#fff', fontSize: '1.1rem', lineHeight: '1.6' }}>
            {result}
          </div>
        </div>
      )}
    </div>
  );
}

export default Workflows;
